// Nodo para transformar el valor de Value a número (0 o 1)
let val = msg.payload["Value"];

if (typeof val === "boolean") {
    msg.payload["Value"] = val ? 1 : 0;
} else if (typeof val === "string") {
    let normalized = val.toLowerCase();
    if (normalized === "true" || normalized === "active") {
        msg.payload["Value"] = 1;
    } else if (normalized === "false" || normalized === "inactive") {
        msg.payload["Value"] = 0;
    }
}

return msg;

// Listado de Dispositivos
var YYYYYYYYYY 
var M = ListadoDevices.length;
var ctx = {};
var TS = [];

// Obtener el payload del mensaje
var data = msg.payload;

// Objeto para almacenar los valores y las cantidades para cada nombre
var valoresPorNombre = {};

// Recorrer el array de elementos
for (var i = 0; i < data.length; i++) {
    var elemento = data[i];
    var nombre = elemento.Nombre;
    var valor = parseFloat(elemento.Valor);
    var timestamp = parseFloat(elemento.ts);
    TS.push(timestamp);
    // Verificar si el nombre ya existe en el objeto
    if (ctx[nombre]) {
        // Si existe, agregamos el valor al total y aumentamos la cantidad
        ctx[nombre].elementos.push(valor);
        ctx[nombre].timestamps.push(timestamp);
        ctx[nombre].total += valor;
        ctx[nombre].cantidad++;
    } else {
        // Si no existe, creamos una nueva entrada en el objeto
        ctx[nombre] = {
            elementos: [valor],
            timestamps: [timestamp],
            total: valor,
            cantidad: 1
        };
    }
}
msg.ctx = ctx;

// Función para calcular la media de los valores de un dispositivo
function calcularMedia(values) {
    if (values.length === 0) return 0;
    var suma = values.reduce(function(total, value){return total +
        value});
    return suma / values.length;
}


// Función para calcular la mediana de los valores de un dispositivo
function calcularMediana(values) {
    // Si no hay valores, devolvemos 0
    if (values.length === 0) return 0;

    // Ordenamos los valores de menor a mayor
    values.sort(function(a, b) {
        return a - b;
    });

    // Calculamos el índice central
    var mitad = Math.floor(values.length / 2);

    // Si la cantidad de valores es impar, devolvemos el valor en la mitad
    if (values.length % 2 !== 0) {
        return values[mitad];
    } 
    // Si la cantidad de valores es par, devolvemos el promedio de los dos valores centrales
    else {
        return (values[mitad - 1] + values[mitad]) / 2;
    }
}


var NewMsg = {timestamp:0};
var NewMsg2 = {timestamp:0};
//Bucle de creación de medias
for (var j=0; j<M; j++){
    var deviceName = ListadoDevices[j];
    if(deviceName in ctx){
        NewMsg[deviceName] = calcularMedia(ctx[deviceName].elementos);
        NewMsg2[deviceName] = calcularMediana(ctx[deviceName].elementos);
    } else {
        NewMsg[deviceName] = NaN;
        NewMsg2[deviceName] = NaN;
    }
}


//Incluimos timestamps minimos y máximos
var ts_min = Math.min.apply(Math,TS);
var ts_max = Math.max.apply(Math, TS);

NewMsg["ts_min"] = ts_min;
NewMsg["ts_max"] = ts_max;
NewMsg["timestamp"] = ts_max;

NewMsg2["ts_min"] = ts_min;
NewMsg2["ts_max"] = ts_max;
NewMsg2["timestamp"] = ts_max;


msg.NewmsgMedias = NewMsg;
msg.NewmsgMediana = NewMsg2;

return msg;

// Creamos un nuevo mensaje
var Newmsg = {};

// Seleccionamos la información que queremos
Newmsg.payload = msg.NewmsgMediana;

// Eliminamos los campos no deseados
delete Newmsg.payload['ts_min'];
delete Newmsg.payload['ts_max'];

return Newmsg;

